/** Nomes exatos da biblioteca — injetados no prompt da IA como allowlist. */
export const EXERCISE_LIBRARY_NAMES: string[] = EXERCISE_GIFS.map((e) => e.name)

/** Normaliza nome p/ casar variações (minúsculas, sem acento, sem parênteses, espaços colapsados). */
function normalizeExerciseName(s: string): string {
  return s
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\([^)]*\)/g, ' ')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim()
}

const GIF_BY_NORM: Map<string, ExerciseGif> = new Map(
  EXERCISE_GIFS.map((e) => [normalizeExerciseName(e.name), e]),
)

/** Acha o GIF de um exercício pelo nome: match exato normalizado, depois por contção. */
export function findExerciseGif(name: string): ExerciseGif | undefined {
  const norm = normalizeExerciseName(name)
  if (!norm) return undefined
  const exact = GIF_BY_NORM.get(norm)
  if (exact) return exact
  for (const e of EXERCISE_GIFS) {
    const en = normalizeExerciseName(e.name)
    if (norm.includes(en) || en.includes(norm)) return e
  }
  return undefined
}
